                                    }
                                ]
                            },
                            {
                                "linkId": "35",
                                "text": "<p>Millainen on yleisvointisi?</p>",
                                "answer": [
                                    {
                                        "valueCoding": {
                                            "id": "2572",
                                            "display": "Pystyn olemaan jalkeilla, mutta selviydyn vain pakollisista kotiaskareista"
                                        }
                                    }
                                ]
                            },
                            {
                                "linkId": "139",
                                "text": "<h1>Muut oireet</h1>\n<p>Vastaa kaikkien oireiden osalta kyllä tai ei</p>"
                            },
                            {
                                "linkId": "141",
                                "text": "<p>Onko sinulla vaikeuksia niellessä (muuta kuin pelkkä kipu)  tai hengittäessä?</p>",
                                "answer": [
                                    {
                                        "valueBoolean": false
                                    }
                                ]
                            },
                            {
                                "linkId": "142",
                                "text": "<p>Onko puheesi tavallisesta poiketen &#34;puuromaista&#34;?</p>",
                                "answer": [
                                    {
                                        "valueBoolean": false
                                    }
                                ]
                            },
                            {
                                "linkId": "143",
                                "text": "<p>Onko sinulla vaikeutta avata suutasi (ns. leukalukko)?</p>",
                                "answer": [
                                    {
                                        "valueBoolean": false
                                    }
                                ]
                            },
                            {
                                "linkId": "144",
                                "text": "<p>Paheneeko kurkkukipu tai vaikeutuuko hengittäminen maatessasi selälläsi?</p>",
                                "answer": [
                                    {
                                        "valueBoolean": false
                                    }
                                ]
                            },
