                  {
                    "valueCoding": {
                      "id": "2472",
                      "display": "Ei"
                    }
                  }
                ]
              },
              {
                "linkId": "89",
                "text": "<p>Onko sinulla muita oireita samanaikaisesti korvakivun kanssa?</p>",
